#!/usr/bin/env python3
"""DirXplore iOS Project Generator
Generates the complete Xcode project files.
"""

import os
import base64

PROJECT_DIR = "DirXplore"

FILES_B64 = {

    "DirXplore.xcodeproj/project.pbxproj": "",
    "DirXploreApp.swift": "",
    "Models/AppPreferences.swift": "",
    "Models/DownloadItem.swift": "",
    "Models/FavoriteItem.swift": "",
    "Models/FileItem.swift": "",
    "Models/HistoryItem.swift": "",
    "Models/TorrentItem.swift": "",
    "Resources/Assets.xcassets/AccentColor.colorset/Contents.json": "",
    "Resources/Assets.xcassets/AppIcon.appiconset/Contents.json": "",
    "Resources/Assets.xcassets/Contents.json": "ewogICJpbmZvIiA6IHsKICAgICJhdXRob3IiIDogInhjb2RlIiwKICAgICJ2ZXJzaW9uIiA6IDEKICB9Cn0K",
    "Resources/DirXplore.entitlements": "",
    "Resources/Info.plist": "",
    "Services/CrawlerService.swift": "",
    "Services/DownloadService.swift": "",
    "Services/HapticsManager.swift": "",
    "Services/SecurityManager.swift": "",
    "Services/TorrentService.swift": "",
    "ViewModels/BrowserViewModel.swift": "",
    "ViewModels/CrawlerViewModel.swift": "",
    "ViewModels/DownloadManagerViewModel.swift": "",
    "ViewModels/SecurityViewModel.swift": "",
    "ViewModels/TorrentViewModel.swift": "",
    "Views/Browser/BrowserView.swift": "",
    "Views/Browser/CrawlerView.swift": "",
    "Views/Browser/DirectoryListView.swift": "",
    "Views/Downloads/DownloadDetailView.swift": "",
    "Views/Downloads/DownloadsView.swift": "",
    "Views/Favorites/FavoritesView.swift": "",
    "Views/MainTabView.swift": "",
    "Views/Media/CustomMediaPlayerView.swift": "",
    "Views/Security/SecurityLockView.swift": "",
    "Views/Settings/DiagnosticsView.swift": "",
    "Views/Settings/SettingsView.swift": "",
    "Views/Torrent/TorrentDetailView.swift": "",
    "Views/Torrent/TorrentHubView.swift": "",
    "Views/Torrent/TorrentSearchView.swift": "",

}


def main():
    for rel_path, b64 in FILES_B64.items():
        content = base64.b64decode(b64).decode("utf-8")
        full_path = os.path.join(PROJECT_DIR, rel_path)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        with open(full_path, "w", encoding="utf-8", newline="\n") as f:
            f.write(content)
        print(f"  Created {rel_path}")
    print(f"\nDone. Project in '{PROJECT_DIR}/'")


if __name__ == "__main__":
    main()
